value.pages_scrapped:
={{ (() => {
  const maxEpoch = $('Input Parameters').item.json.maxEpoch;
  const list = $('Input Parameters').item.json.job_portal_list;
  const epoch = $('Save Video Details').item.json.epoch;
  const index = epoch % Math.floor(maxEpoch / list.length);

  return (!$('Updated Input Parameters').isExecuted || index == 0)
    ? 0
    : $('Updated Input Parameters').item.json.pages_scrapped;
})() }}

value.job_portal:
={{ (() => {
  const maxEpoch = $('Input Parameters').item.json.maxEpoch;
  const list = $('Input Parameters').item.json.job_portal_list;
  const epoch = $('Save Video Details').item.json.epoch;
  const index = Math.floor(epoch / Math.floor(maxEpoch / list.length));
  return list[index];
})() }}

parameters.jsCode:
const batch_size = $('Input Parameters').first().json.batch_size;
let filename_list = []
const final_filename_list = []
let index = 0;

for (const item of $input.all()) {
  if (index === batch_size) {
    final_filename_list.push({
      "video_file_name": filename_list
    });
    filename_list = [];
    index = 0;
  }
  filename_list.push(item.json.filename);
  index += 1;
}

if (filename_list.length !== 0) {
  final_filename_list.push({
    "video_file_name": filename_list
  });
}

return {
  json: {
    output: final_filename_list,
    id: $('Save Video Details').first().json.id,
    date: $('Save Video Details').first().json.date,
    epoch: parseInt($('Save Video Details').first().json.epoch, 10)
  },
  pairedItem: []
}

